UPDATE `order` SET
status = #{data.status}, refund_amount = #{data.refundAmount}, refund_time = #{data.refundTime},
WHERE order_type = #{data.orderType} AND order_id = #{data.orderId}

mapper.select:
SELECT *
FROM `order`
WHERE order_type = #{orderType}
AND order_id = #{orderId}

SELECT *
FROM `order`

    AND user_id = #{param.searchField1}

        AND `order_type` IN

            #{item}



        AND `status` IN

            #{item}


    AND `status` = #{param.searchIntStatus}
    AND `divide_status` = #{param.searchField2}
    AND `shop_id` = #{param.searchField3}

        AND `order_no` LIKE CONCAT('%', #{param.searchStrField1}, '%')


        AND (phone LIKE CONCAT('%',#{param.keyword},'%') OR nick_name LIKE CONCAT('%',#{param.keyword},'%'))


        AND `pay_time` >= #{param.limitTime}


        AND `create_time` BETWEEN #{param.startTime} AND #{param.endTime}


ORDER BY `id` desc

SELECT
COUNT(*) AS orderCount,
IFNULL(
(SELECT IFNULL(SUM(amount), 0) FROM `order` WHERE `shop_id` = #{param.searchField4} AND `status` = 1

    AND `create_time` BETWEEN #{param.startTime} AND #{param.endTime}

)
-
(SELECT IFNULL(SUM(refund_amount), 0) FROM `order` WHERE `shop_id` = #{param.searchField4} AND `status` = 2

    AND `create_time` BETWEEN #{param.startTime} AND #{param.endTime}

),
0
) AS revenue,
IFNULL(
(SELECT IFNULL(SUM(amount), 0) FROM `order` WHERE `shop_id` = #{param.searchField4} AND `divide_status` = 0),
0
) AS pendingAmount
FROM `order`
WHERE `shop_id` = #{param.searchField4}

    AND `create_time` BETWEEN #{param.startTime} AND #{param.endTime}
